  ('diplomatic-1c87f27b-moex-00579', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-110-e6f33b51', 'sub-diplomatic-1c87f27b-02', NULL, 'single_choice', '假設兩國生產技術與需求相近條件下，美國的資本／勞動（capital/labor）因素稟賦（factor endowment）比例是0.5，中國的資本／勞動比是0.02。則與中國相比較時，下列何者關於美國的 資本使用成本相對於其勞動使用成本是正確的？', '["偏高的", "偏低的", "無差異的", "無法比較"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:03+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
  ('diplomatic-1c87f27b-moex-00580', 'diplomatic-1c87f27b', 'diplomatic-1c87f27b-moex-110-e6f33b51', 'sub-diplomatic-1c87f27b-02', NULL, 'single_choice', '小國對於進口汽車數量的限制可以透過課徵關稅（tariffs）或進口配額（quota）的措施完成。A國 課徵進口關稅所限制進口的汽車數量與實施進口配額限制的數量一樣，則當A國國內汽車需求增 加時，在分別實施關稅與進口配額之情況下，國內汽車均衡價格各會如何改變？', '["不變，不變", "上升，下降", "不變，上升", "不確定，不確定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:03+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-土耳其文組"}'::jsonb, NULL),
